    //   V[4] ↔ α · β^2 · p^{-7} · (s|T|s)
    //   V[5] ↔ β · p^{-6} · (s|T|s)
    //   V[6] ↔ α^5 · β^6 · p^{-11} · ξ · (s|S|s)
    //   V[7] ↔ α^4 · β^5 · p^{-10} · ξ · (s|S|s)
    //   V[8] ↔ α^3 · β^4 · p^{-9} · ξ · (s|S|s)
